using ExpenseTracker.Application.Interfaces; using ExpenseTracker.Domain.Entities; using Microsoft.EntityFrameworkCore; using ExpenseTracker.Infrastructure.Persistence;
namespace ExpenseTracker.Infrastructure.Repositories;
public sealed class UserRepository(ExpenseTrackerDbContext db):IUserRepository { public Task<User?> ByEmail(string email)=>db.Users.FirstOrDefaultAsync(x=>x.Email==email); public Task<User?> Get(Guid id)=>db.Users.FindAsync(id).AsTask(); public Task Add(User x)=>db.Users.AddAsync(x).AsTask(); public Task Save()=>db.SaveChangesAsync(); }
public sealed class CategoryRepository(ExpenseTrackerDbContext db):ICategoryRepository { public Task<List<Category>> List(Guid u)=>db.Categories.AsNoTracking().Where(x=>x.UserId==u).ToListAsync(); public Task<Category?> Get(Guid id,Guid u)=>db.Categories.FirstOrDefaultAsync(x=>x.Id==id&&x.UserId==u); public Task Add(Category x)=>db.Categories.AddAsync(x).AsTask(); public void Delete(Category x)=>db.Categories.Remove(x); public Task Save()=>db.SaveChangesAsync(); }
public sealed class TransactionRepository(ExpenseTrackerDbContext db):ITransactionRepository { public Task<List<Transaction>> List(Guid u)=>db.Transactions.AsNoTracking().Where(x=>x.UserId==u).OrderByDescending(x=>x.Date).ToListAsync(); public Task<Transaction?> Get(Guid id,Guid u)=>db.Transactions.FirstOrDefaultAsync(x=>x.Id==id&&x.UserId==u); public Task Add(Transaction x)=>db.Transactions.AddAsync(x).AsTask(); public void Delete(Transaction x)=>db.Transactions.Remove(x); public Task Save()=>db.SaveChangesAsync(); }
public sealed class BudgetRepository(ExpenseTrackerDbContext db):IBudgetRepository { public Task<List<Budget>> List(Guid u)=>db.Budgets.AsNoTracking().Where(x=>x.UserId==u).ToListAsync(); public Task<Budget?> Get(Guid id,Guid u)=>db.Budgets.FirstOrDefaultAsync(x=>x.Id==id&&x.UserId==u); public Task Add(Budget x)=>db.Budgets.AddAsync(x).AsTask(); public void Delete(Budget x)=>db.Budgets.Remove(x); public Task Save()=>db.SaveChangesAsync(); }
public sealed class RefreshTokenRepository(ExpenseTrackerDbContext db):IRefreshTokenRepository { public Task<RefreshToken?> Find(string token)=>db.RefreshTokens.FirstOrDefaultAsync(x=>x.Token==token); public Task Add(RefreshToken x)=>db.RefreshTokens.AddAsync(x).AsTask(); public Task Save()=>db.SaveChangesAsync(); }
